import openai
from getpass import getpass

# Replace YOUR_API_KEY with your actual OpenAI API key
openai.api_key = "YOUR_API_KEY"

def generate_response(prompt):
    response = openai.Completion.create(
        engine="text-davinci-002",
        prompt=prompt,
        max_tokens=1024,
        n=1,
        stop=None,
        temperature=0.5,
    )

    message = response.choices[0].text
    return message.strip()

def chatbot():
    print("Welcome to our customer support assistant!")
    
    while True:
        user_message = getpass("User: ")  # The input function masks the actual message being typed in console
        system_instructions = "You are a customer support assistant. We value your time and provide quick, accurate answers to all queries."
        
        if user_message.lower() == 'quit':
            print("Customer Support Assistant: Goodbye!")
            break
            
        prompt = f"{system_instructions} User said: {user_message}"
        response = generate_response(prompt)
        print(f"Customer Support Assistant: {response}\n")

if __name__ == "__main__":
    chatbot()